/**
 * Prisma Retry Helper
 * Автоматическое переподключение при ошибке P1017 (Server has closed the connection)
 */

import { prisma } from './prisma'

/**
 * Выполнить Prisma запрос с автоматическим retry при ошибке соединения
 */
export async function withPrismaRetry<T>(
  operation: () => Promise<T>,
  maxRetries = 3
): Promise<T> {
  let lastError: any
  
  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    try {
      return await operation()
    } catch (error: any) {
      lastError = error
      
      // Проверяем, это ошибка соединения (закрыто, пул исчерпан, сброс)
      const isConnectionError =
        error?.code === 'P1017' ||
        error?.code === 'P2024' ||
        error?.message?.includes('Server has closed the connection') ||
        error?.message?.includes('Connection terminated unexpectedly') ||
        error?.message?.includes('Timed out fetching a new connection') ||
        error?.message?.includes('ConnectionReset') ||
        error?.message?.includes('max clients reached')
      
      if (!isConnectionError) {
        // Это не ошибка соединения, пробрасываем дальше
        throw error
      }
      
      console.warn(`[Prisma Retry] Connection error on attempt ${attempt}/${maxRetries}`)
      
      if (attempt < maxRetries) {
        // Пытаемся переподключиться
        console.log(`[Prisma Retry] Reconnecting...`)
        try {
          await prisma.$disconnect()
          await prisma.$connect()
        } catch (reconnectError: any) {
          console.error(`[Prisma Retry] Reconnection failed:`, reconnectError.message)
        }
        
        // Экспоненциальная задержка: 500ms, 1s, 2s
        await new Promise(resolve => setTimeout(resolve, 500 * attempt))
      }
    }
  }
  
  console.error(`[Prisma Retry] All ${maxRetries} attempts failed`)
  throw lastError
}

