import { createMiddlewareClient } from '@supabase/auth-helpers-nextjs'
import { NextResponse } from 'next/server'
import type { NextRequest } from 'next/server'

export async function middleware(req: NextRequest) {
  const res = NextResponse.next()

  // В режиме разработки пропускаем проверку авторизации
  if (process.env.NODE_ENV === 'development' && process.env.SKIP_AUTH === 'true') {
    return res
  }

  const supabase = createMiddlewareClient({ req, res })

  const {
    data: { session },
  } = await supabase.auth.getSession()

  // Protected routes
  const protectedPaths = ['/dashboard', '/goals', '/learn', '/graph', '/review', '/chat', '/stats', '/settings', '/profile']
  const isProtectedPath = protectedPaths.some(path => req.nextUrl.pathname.startsWith(path))

  // Require auth for protected routes
  if (isProtectedPath && !session) {
    return NextResponse.redirect(new URL('/login', req.url))
  }

  // Redirect logged in users from auth pages to dashboard
  const authPages = ['/login', '/register']
  if (authPages.includes(req.nextUrl.pathname) && session) {
    return NextResponse.redirect(new URL('/dashboard', req.url))
  }

  return res
}

export const config = {
  matcher: ['/((?!_next/static|_next/image|favicon.ico|api).*)'],
}

import { createServerClient } from '@/lib/supabase/server'
import { prisma } from '@/lib/prisma'
import { withPrismaRetry } from '@/lib/prisma-retry'

export async function getCurrentUser() {
  // В режиме разработки с SKIP_AUTH возвращаем тестового пользователя
  if (process.env.NODE_ENV === 'development' && process.env.SKIP_AUTH === 'true') {
    return withPrismaRetry(async () => {
      let user = await prisma.user.findFirst()

      if (!user) {
        // Создаём тестового пользователя если его нет
        user = await prisma.user.create({
          data: {
            email: 'test@example.com',
            name: 'Test User',
          },
        })
      }

      return user
    })
  }

  const supabase = createServerClient()
  const { data: { session } } = await supabase.auth.getSession()

  if (!session?.user?.email) {
    return null
  }

  // Find or create user with retry
  return withPrismaRetry(async () => {
    let user = await prisma.user.findUnique({
      where: { email: session.user.email },
    })

    if (!user) {
      const email = session.user.email ?? ''
      user = await prisma.user.create({
        data: {
          email,
          name: session.user.user_metadata?.full_name || email.split('@')[0],
          avatar: session.user.user_metadata?.avatar_url,
        },
      })
    }

    return user
  })

